import { ApiProperty } from '@nestjs/swagger'
import { IsNotEmpty, IsString } from 'class-validator'

export class LiqPayCallback {
	@IsString()
	@IsNotEmpty()
	@ApiProperty({
		example:
			''
	})
	public data: string

	@IsString()
	@IsNotEmpty()
	@ApiProperty({ example: 'CowAKWs2uV83Bzc8Xb38upXVGlywlwLNnti/oLK4GGU=' })
	public signature: string
}
